if (Array.isArray(historialResponse)) {
  mensajes = historialResponse;
} else if (historialResponse.payload && Array.isArray(historialResponse.payload)) {
  mensajes = historialResponse.payload;
} else if (historialResponse.data && Array.isArray(historialResponse.data)) {
  mensajes = historialResponse.data;
}

console.log('Total mensajes encontrados en historial:', mensajes.length);

if (mensajes.length === 0) {
  return [{
    json: {
      contextoManual: '',
      sinMensajes: true,
      from,
      contactName
    }
  }];
}

// ==============================
// ORDENAR (más antiguos primero)
// ==============================
mensajes.sort((a, b) => {
  const tA = a.created_at || 0;
  const tB = b.created_at || 0;
  return tA - tB;
});

// ==============================
// TOMAR ÚLTIMOS 10 MENSAJES
// ==============================
const mensajesRecientes = mensajes.slice(-10);

console.log('Mensajes a procesar (últimos 10):', mensajesRecientes.length);

// ==============================
// FORMATEAR CONVERSACIÓN
// ==============================
const conversacion = mensajesRecientes
  .map(msg => {
    // Ignorar mensajes de actividad (message_type: 2)
    if (msg.message_type === 2) {
      return null;
    }

    // Determinar si es del cliente o del agente
    // message_type: 0 = incoming (cliente)
    // message_type: 1 = outgoing (agente/bot)
    const esCliente = msg.message_type === 0;

    let contenido = msg.content || '';

    // Manejar attachments
    if (msg.attachments && msg.attachments.length > 0) {
      const attachment = msg.attachments[0];
      if (attachment.file_type === 'image') {
        contenido = `[Imagen${contenido ? ': ' + contenido : ''}]`;
      } else if (attachment.file_type === 'audio') {
        contenido = '[Audio]';
      } else if (attachment.file_type === 'video') {
        contenido = '[Video]';
      } else if (attachment.file_type === 'file') {
        contenido = `[Documento${contenido ? ': ' + contenido : ''}]`;
      } else {
        contenido = `[${attachment.file_type}]`;
      }
    }

    // Si no hay contenido, saltar
    if (!contenido) {
      return null;
    }

    const quien = esCliente ? 'CLIENTE' : 'TÚ (ANDRÉS)';

    // Convertir timestamp Unix a fecha legible (Argentina)
    const fecha = new Date(msg.created_at * 1000);
    const timestamp = fecha.toLocaleString('es-AR', {
      timeZone: 'America/Argentina/Buenos_Aires',
      day: '2-digit',
      month: '2-digit',
      hour: '2-digit',
      minute: '2-digit'
    });

    return `[${timestamp}] ${quien}: ${contenido}`;
