      const zonaCandidato = zonaMatch[1] ? zonaMatch[1].trim() : zonaMatch[0].trim();
      if (zonaCandidato.length > 2 && zonaCandidato.length < 50) {
        info.zona = zonaCandidato.charAt(0).toUpperCase() + zonaCandidato.slice(1);
        console.log('Zona encontrada:', info.zona);
        break;
      }
    }
  }

  // Extraer forma de pago
  if (fullContext.match(/\b(contado|efectivo|cash|al contado|pago contado|en efectivo|seria en efectivo|compra seria en efectivo)\b/)) {
    info.forma_pago = 'contado';
    console.log('Forma de pago: contado');
  } else if (fullContext.match(/\b(financiado|financiación|cuotas|en cuotas|crédito|a crédito)\b/)) {
    info.forma_pago = 'financiado';
  } else if (fullContext.match(/\b(hipotecario|préstamo|préstamo hipotecario|con hipoteca|por banco|busqueda es por banco)\b/)) {
    info.forma_pago = 'hipotecario';
  } else if (fullContext.match(/\b(mixto|parte contado|parte financiado)\b/)) {
    info.forma_pago = 'mixto';
  }

  // Extraer características buscadas
  const caracBuscadas = [];

  const ambMatch = fullContext.match(/\b(\d+)\s*(?:ambiente|ambientes|amb)\b/);
  if (ambMatch) {
    caracBuscadas.push(`${ambMatch[1]} ambientes`);
  }

  const dormMatch = fullContext.match(/\b(\d+)\s*(?:dormitorio|dormitorios|habitación|habitaciones|cuarto|cuartos)\b/);
  if (dormMatch) {
    caracBuscadas.push(`${dormMatch[1]} dormitorios`);
  }

  const bañoMatch = fullContext.match(/\b(\d+)\s*(?:baño|baños)\b/);
  if (bañoMatch) {
    caracBuscadas.push(`${bañoMatch[1]} baños`);
  }

  const extrasRegex = /\b(balcón|balcon|terraza|jardín|jardin|patio|parrilla|quincho|cochera|garage|amenities|gym|gimnasio|piscina|pileta|sum|lavadero|baulera)\b/g;
  const extras = fullContext.match(extrasRegex);
  if (extras) {
    caracBuscadas.push(...[...new Set(extras)]);
  }

  if (caracBuscadas.length > 0) {
    info.caracteristicas_buscadas = caracBuscadas.join(', ');
    console.log('Características:', info.caracteristicas_buscadas);
  }

  // ═══════════════════════════════════════════
  // ETIQUETADO CANÓNICO de propiedad_interes
  // Fingerprint numérico contra tabla `pautas`
  // ═══════════════════════════════════════════
  const numericFingerprint = (text) => {
    const matches = String(text || '').match(/\d+/g);
    if (!matches || matches.length === 0) return [];
    return [...new Set(matches.map(n => parseInt(n, 10)))].sort((a, b) => a - b);
  };

  const pautas = $('fetch pautas').first()?.json?.pautas || [];
  const userFp = numericFingerprint(userMsg);

  if (userFp.length >= 2 && pautas.length > 0) {
    let bestMatch = null;
    let bestSize = 0;
    for (const p of pautas) {
      const pFp = numericFingerprint(p.texto);
      if (pFp.length < 2) continue; // ignora pautas con <2 números (falsos positivos)
      if (pFp.every(n => userFp.includes(n)) && pFp.length > bestSize) {
        bestMatch = p;
        bestSize = pFp.length;
      }
    }
    if (bestMatch) {
      info.propiedad_interes = bestMatch.texto;
      console.log(`✅ Pauta canónica matcheada: "${bestMatch.texto}" (${bestSize} números)`);
    } else {
      console.log('ℹ sin match canónico contra pautas; propiedad_interes queda null');
    }
  } else {
    console.log('ℹ mensaje sin suficientes números (<2) o sin pautas activas');
  }

  // 🆕 EXTRAER NOMBRE - CON PUSHNAME COMO FALLBACK
  const nombreMatch = userMsg.match(/\b(?:me llamo|mi nombre es|soy|mi nombre)\s+([a-záéíóúñ]+(?:\s+[a-záéíóúñ]+)?)/i);
  if (nombreMatch) {
    const nombre = nombreMatch[1].trim();
    info.nombre = nombre.split(' ').map(word => 
      word.charAt(0).toUpperCase() + word.slice(1).toLowerCase()
    ).join(' ');
    console.log('✅ Nombre del mensaje:', info.nombre);
  } else if (pushName) {
    info.nombre = pushName.trim();
    console.log('✅ Nombre del pushName de Chatwoot:', info.nombre);
  }

  return info;
}

// Extraer información del lead
const leadInfo = extractLeadInfo(userMessage, agentOutput);

console.log('=== LEAD INFO FINAL ===');
console.log(JSON.stringify(leadInfo, null, 2));

// Construir query SQL - solo con campos no nulos
const fields = [];
const values = [];
const updates = [];

// 🔒 Allowlist: solo estos campos llegan al UPSERT. El resto de la extracción
// (intencion, tipo_propiedad, presupuesto, zona, forma_pago, caracteristicas_buscadas,
//  caracteristicas_venta) corre pero NO se persiste en leads.
const ALLOWED_FIELDS = ['nombre', 'estado', 'ultima_interaccion', 'propiedad_interes'];

Object.entries(leadInfo).forEach(([key, value]) => {
  if (value !== null && key !== 'whatsapp_id' && ALLOWED_FIELDS.includes(key)) {
    fields.push(key);
    values.push(value);

    if (key === 'estado') {
      // 🔒 PROTECCIÓN: llamada, busqueda y visita nunca se pisan desde el UPSERT
      updates.push(`${key} = CASE 
        WHEN leads.${key} IN ('llamada', 'visita', 'busqueda') THEN leads.${key}
        WHEN EXCLUDED.${key} = 'caliente' THEN 'caliente'
        WHEN EXCLUDED.${key} = 'tibio' AND leads.${key} NOT IN ('caliente', 'llamada', 'visita', 'busqueda') THEN 'tibio'
        WHEN leads.${key} IS NULL OR leads.${key} IN ('activo', 'inicial', '') THEN EXCLUDED.${key}
        ELSE COALESCE(EXCLUDED.${key}, leads.${key})
      END`);
    } else if (key === 'ultima_interaccion') {
      updates.push(`${key} = EXCLUDED.${key}`);
    } else if (key === 'propiedad_interes') {
      // actualiza si hay nuevo match; si null, preserva el valor existente
      updates.push(`${key} = COALESCE(EXCLUDED.${key}, leads.${key})`);
    } else {
      // nombre: write-once — solo escribe si en BD está NULL o ''
      updates.push(`${key} = COALESCE(NULLIF(leads.${key}, ''), EXCLUDED.${key})`);
    }
  }
});

// Si no hay campos, solo actualizar ultima_interaccion
if (fields.length === 0) {
  fields.push('ultima_interaccion');
  values.push(leadInfo.ultima_interaccion);
  updates.push('ultima_interaccion = EXCLUDED.ultima_interaccion');
}

const query = `
INSERT INTO leads (whatsapp_id, ${fields.join(', ')})
VALUES ($1, ${values.map((_, i) => `$${i + 2}`).join(', ')})
ON CONFLICT (whatsapp_id) 
DO UPDATE SET 
  ${updates.join(',\n  ')},
  updated_at = CURRENT_TIMESTAMP
RETURNING *;
`;

const parameters = [leadInfo.whatsapp_id, ...values];

console.log('=== QUERY FINAL ===');
console.log('Campos a actualizar:', fields);
console.log('Valores:', parameters);

return [{
  json: {
    query: query,
    parameters: parameters,
    leadInfo: leadInfo,
    operation: 'upsert',
    whatsapp_id: leadInfo.whatsapp_id,
    extracted_data: {
      user_message: userMessage.substring(0, 200),
      agent_response: agentOutput.substring(0, 200),
      pushName: pushName
    },
    debug: {
      whatsapp_found: !!whatsappId,
      pushname_found: !!pushName,
      fields_updated: fields,
      user_msg_length: userMessage.length,
      agent_msg_length: agentOutput.length
    }
  }
}];

// ============================================
// NORMALIZAR WEBHOOKS - VERSIÓN SIMPLE Y SEGURA
// ============================================

try {
  const webhookData = $input.first().json;
  const body = webhookData.body;
  const event = body.event;

  console.log('=== WEBHOOK RECIBIDO ===');
  console.log('Event:', event);

  // ============================================
  // NORMALIZACIÓN BÁSICA
  // ============================================

  let normalized = {
    event: event,
    account: body.account || null,
    inbox: body.inbox || null,
    conversation: null,
    message: null,
    sender: null,
    content: null,
    source_id: null,
    timestamp: null
  };

  if (event === 'conversation_created') {
    // Conversación está en body directamente
    normalized.conversation = {
      id: body.id,
      inbox_id: body.inbox_id,
      status: body.status,
      contact_inbox: body.contact_inbox,
      messages: body.messages || [],
      meta: body.meta,
      created_at: body.created_at,
      updated_at: body.updated_at
    };

    const firstMessage = body.messages?.[0];
    if (firstMessage) {
      normalized.message = firstMessage;
      normalized.content = firstMessage.content;
      normalized.source_id = firstMessage.source_id;
      normalized.timestamp = firstMessage.created_at;
      normalized.sender = firstMessage.sender;
    }

  } else if (event === 'message_created') {
    // Conversación está en body.conversation
    normalized.conversation = body.conversation;
    normalized.message = {
      id: body.id,
      content: body.content,
      message_type: body.message_type,
      created_at: body.created_at,
      source_id: body.source_id,
      sender_id: body.sender?.id
    };
    normalized.content = body.content;
    normalized.source_id = body.source_id;
    normalized.timestamp = body.created_at;
    normalized.sender = body.sender;
  }

  // Datos comunes
  normalized.phone_number = normalized.conversation?.contact_inbox?.source_id;
  normalized.whatsapp_id = normalized.phone_number?.replace('+', '');
  normalized.contact_name = normalized.sender?.name || 'Desconocido';
  normalized.conversation_id = normalized.conversation?.id;
  normalized.inbox_id = normalized.conversation?.inbox_id;

  console.log('Normalizado exitosamente');
  console.log('Teléfono:', normalized.phone_number);
  console.log('Evento:', event);

  return [{
    json: {
      ...webhookData,
      normalized: normalized
    }
  }];

} catch (error) {
  console.error('ERROR EN NORMALIZACIÓN:', error.message);
  console.error('Stack:', error.stack);
  throw error;
}

